import strawberry
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, Float
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship, backref

Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    price = Column(Float, nullable=False)
    category_id = Column(Integer, ForeignKey('categories.id'))
    seller_id = Column(Integer, ForeignKey('sellers.id'))
    images = relationship('Image', backref='product')
    reviews = relationship('Review', backref='product')

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    user_name = Column(String, nullable=False)
    rating = Column(Float, nullable=False)
    comment = Column(String)

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False)
    products = relationship('Product', backref='category')

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    url = Column(String, nullable=False)

engine = create_engine('sqlite:///example.db')
Base.metadata.create_all(engine)
Session = sessionmaker(bind=engine)

@strawberry.type
class ProductType:
    id: strawberry.ID
    name: str
    price: float
    category: 'CategoryType'
    seller: 'SellerType'
    images: list['ImageType']
    reviews: list['ReviewType']

@strawberry.type
class ReviewType:
    id: strawberry.ID
    product: ProductType
    user_name: str
    rating: float
    comment: str

@strawberry.type
class CategoryType:
    id: strawberry.ID
    name: str
    products: list[ProductType]

@strawberry.type
class ImageType:
    id: strawberry.ID
    product: ProductType
    url: str

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, product_id: strawberry.ID) -> ProductType:
        session = Session()
        product = session.query(Product).get(product_id)
        return ProductType(
            id=product.id,
            name=product.name,
            price=product.price,
            category=CategoryType(id=product.category.id, name=product.category.name),
            seller=SellerType(id=product.seller.id, name=product.seller.name),  # Assuming SellerType is defined elsewhere
            images=[ImageType(id=image.id, url=image.url) for image in product.images],
            reviews=[ReviewType(id=review.id, user_name=review.user_name, rating=review.rating, comment=review.comment) for review in product.reviews]
        )

schema = strawberry.Schema(query=Query)